from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body into a single fluent sentence.
    The function assumes all triples refer to the same subject (the celestial body).
    """
    if not triples:
        return ""

    # All triples are expected to share the same subject
    subject = triples[0].subject

    def phrase(t: Triple) -> str:
        p = t.predicate
        o = t.object.strip()
        # Helper to keep unit text if present
        obj = o

        # Mapping predicates to natural language fragments
        if p == "apoapsis":
            return f"has an apoapsis of {obj}"
        if p == "periapsis":
            return f"has a periapsis of {obj}"
        if p == "orbitalPeriod":
            return f"orbits in {obj}"
        if p == "epoch":
            return f"was recorded on {obj}"
        if p == "discoverer":
            return f"was discovered by {obj}"
        if p == "discovered":
            return f"was discovered on {obj}"
        if p == "mass":
            return f"has a mass of {obj}"
        if p == "averageSpeed":
            return f"travels at an average speed of {obj}"
        if p == "escapeVelocity":
            return f"has an escape velocity of {obj}"
        if p == "temperature":
            return f"has a temperature of {obj}"
        if p == "density":
            return f"has a density of {obj}"
        if p == "rotationPeriod":
            return f"rotates every {obj}"
        if p == "maximumTemperature":
            return f"reaches a maximum temperature of {obj}"
        if p == "meanTemperature":
            return f"has a mean temperature of {obj}"
        if p == "minimumTemperature":
            return f"has a minimum temperature of {obj}"
        if p == "formerName":
            return f"was formerly known as {obj}"
        if p == "absoluteMagnitude":
            return f"has an absolute magnitude of {obj}"
        if p == "surfaceArea":
            return f"covers a surface area of {obj}"
        if p == "deathCause":
            return f"died of {obj}"
        if p == "deathPlace":
            return f"died in {obj}"
        if p in ("nationality", "stateOfOrigin"):
            return f"is {obj}"
        if p == "almaMater":
            return f"studied at {obj}"
        if p == "birthPlace":
            return f"was born in {obj}"
        if p == "doctoralStudent":
            return f"supervised {obj}"
        if p == "deathDate":
            return f"died on {obj}"
        if p == "birthDate":
            return f"was born on {obj}"
        # Fallback for any other predicate
        return f"{p} {obj}"

    # Build a phrase for each triple
    phrases = [phrase(t) for t in triples]

    # Join the phrases into a fluent list
    if len(phrases) == 1:
        body = phrases[0]
    else:
        body = ", ".join(phrases[:-1]) + ", and " + phrases[-1]

    return f"{subject} {body}."

# EVOLVE-BLOCK-END
